module counter7bit_load (
    input clk,
    input rst,
    input load,
    input [6:0] d,
    output [6:0] q
);

    reg [6:0] count_reg;

    always @(posedge clk or posedge rst) begin
        if (rst)
            count_reg <= 7'b0000000;
        else if (load)
            count_reg <= d;
        else
            count_reg <= count_reg + 1;
    end

    assign q = count_reg;

endmodule
